  hipStream_t stream = at::hip::getCurrentHIPStream();
#else
  cudaStream_t stream = at::cuda::getCurrentCUDAStream();
#endif
  three_interpolate_grad_kernel<<<b, opt_block_config(n, c), 0, stream>>>(
      b, c, n, m, grad_out, idx, weight, grad_points);

  CUDA_CHECK_ERRORS();
}

